import React, { createContext, useContext, useState, ReactNode } from 'react';
import { OrderState, OrderContextType } from '../types';
import { MOCK_SOL_PRICE_USD } from '../constants';

const defaultOrder: OrderState = {
  selectedPackage: null,
  walletAddress: '',
  email: '',
  txHash: '',
};

const ShopContext = createContext<OrderContextType | undefined>(undefined);

export const ShopProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [order, setOrder] = useState<OrderState>(defaultOrder);

  const updateOrder = (updates: Partial<OrderState>) => {
    setOrder(prev => ({ ...prev, ...updates }));
  };

  const resetOrder = () => {
    setOrder(defaultOrder);
  };

  return (
    <ShopContext.Provider value={{ order, updateOrder, resetOrder, solPrice: MOCK_SOL_PRICE_USD }}>
      {children}
    </ShopContext.Provider>
  );
};

export const useShop = () => {
  const context = useContext(ShopContext);
  if (!context) {
    throw new Error('useShop must be used within a ShopProvider');
  }
  return context;
};

import React, { useEffect } from 'react';

interface SEOProps {
  title: string;
  description?: string;
}

export const SEO: React.FC<SEOProps> = ({ title, description }) => {
  useEffect(() => {
    document.title = `${title} | Flash USDT Solana`;
    const metaDesc = document.querySelector('meta[name="description"]');
    if (metaDesc) {
      metaDesc.setAttribute('content', description || "Premium Flash USDT packages on Solana.");
    } else {
      const meta = document.createElement('meta');
      meta.name = "description";
      meta.content = description || "Premium Flash USDT packages on Solana.";
      document.head.appendChild(meta);
    }
  }, [title, description]);

  return null;
};

