import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useShop } from '../context/ShopContext';
import { SEO } from '../components/SEO';
import { ArrowLeft, Wallet, Mail } from 'lucide-react';

export const OrderDetails: React.FC = () => {
  const { order, updateOrder } = useShop();
  const navigate = useNavigate();
  const [wallet, setWallet] = useState(order.walletAddress);
  const [email, setEmail] = useState(order.email);
  const [error, setError] = useState('');

  if (!order.selectedPackage) {
    navigate('/');
    return null;
  }

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!wallet || wallet.length < 32) {
      setError('Please enter a valid Solana wallet address.');
      return;
    }
    if (!email || !email.includes('@')) {
      setError('Please enter a valid email address.');
      return;
    }

    updateOrder({ walletAddress: wallet, email });
    navigate('/payment');
  };

  return (
    <div className="min-h-screen pt-12 pb-24 px-4">
      <SEO title="Complete Order" />
      <div className="max-w-lg mx-auto">
        <button 
            onClick={() => navigate(-1)}
            className="flex items-center text-gray-400 hover:text-white mb-8 transition-colors"
        >
            <ArrowLeft size={20} className="mr-2" />
            Back to Packages
        </button>

        <div className="bg-card border border-white/10 rounded-2xl p-6 md:p-8 shadow-xl">
            <h2 className="text-2xl font-bold text-white mb-2">Order Details</h2>
            <p className="text-gray-400 mb-8">
                You selected <span className="text-secondary font-semibold">{order.selectedPackage.flashAmount.toLocaleString()} Flash</span>. 
                Please provide your details for delivery.
            </p>

            <form onSubmit={handleSubmit} className="space-y-6">
                <div>
                    <label className="block text-sm font-medium text-gray-300 mb-2">
                        Receive Address (SOL)
                    </label>
                    <div className="relative">
                        <Wallet className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={20} />
                        <input 
                            type="text" 
                            value={wallet}
                            onChange={(e) => setWallet(e.target.value)}
                            className="w-full bg-dark/50 border border-white/10 rounded-xl py-3 pl-10 pr-4 text-white focus:outline-none focus:border-primary focus:ring-1 focus:ring-primary transition-all"
                            placeholder="Enter your SOL wallet address"
                        />
                    </div>
                </div>

                <div>
                    <label className="block text-sm font-medium text-gray-300 mb-2">
                        Email Address
                    </label>
                    <div className="relative">
                        <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={20} />
                        <input 
                            type="email" 
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            className="w-full bg-dark/50 border border-white/10 rounded-xl py-3 pl-10 pr-4 text-white focus:outline-none focus:border-primary focus:ring-1 focus:ring-primary transition-all"
                            placeholder="name@example.com"
                        />
                    </div>
                    <p className="text-xs text-gray-500 mt-2">We will use this for order updates and support.</p>
                </div>

                {error && (
                    <div className="p-3 bg-red-500/10 border border-red-500/20 rounded-lg text-red-400 text-sm">
                        {error}
                    </div>
                )}

                <button 
                    type="submit"
                    className="w-full bg-gradient-to-r from-primary to-purple-600 text-white font-bold py-4 rounded-xl hover:opacity-90 transition-opacity shadow-lg shadow-primary/20"
                >
                    Next Step
                </button>
            </form>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useShop } from '../context/ShopContext';
import { RECIPIENT_WALLET } from '../constants';
import { SEO } from '../components/SEO';
import { Copy, AlertTriangle, Check, Loader2 } from 'lucide-react';

export const Payment: React.FC = () => {
  const { order, solPrice, updateOrder } = useShop();
  const navigate = useNavigate();
  const [copied, setCopied] = useState(false);
  const [txHash, setTxHash] = useState('');
  const [isVerifying, setIsVerifying] = useState(false);

  if (!order.selectedPackage) {
    navigate('/');
    return null;
  }

  // Calculate SOL amount
  const solAmount = (order.selectedPackage.priceUsd / solPrice).toFixed(4);

  const handleCopy = () => {
    navigator.clipboard.writeText(RECIPIENT_WALLET);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleVerify = (e: React.FormEvent) => {
    e.preventDefault();
    if (!txHash || txHash.length < 10) return;

    setIsVerifying(true);
    // Simulate network verification delay
    setTimeout(() => {
        setIsVerifying(false);
        updateOrder({ txHash });
        navigate('/confirmation');
    }, 2500);
  };

  return (
    <div className="min-h-screen pt-12 pb-24 px-4">
      <SEO title="Payment" />
      <div className="max-w-2xl mx-auto">
        <div className="bg-card border border-white/10 rounded-2xl p-6 md:p-8 shadow-xl">

            {/* Header */}
            <div className="text-center mb-8">
                <h2 className="text-2xl font-bold text-white mb-2">Complete Payment</h2>
                <p className="text-gray-400">Send the exact amount to the address below.</p>
            </div>

            {/* Warning Box */}
            <div className="bg-yellow-500/10 border border-yellow-500/20 rounded-xl p-4 mb-8 flex gap-3">
                <AlertTriangle className="text-yellow-500 shrink-0" size={24} />
                <div className="text-sm text-yellow-200/90">
                    <p className="font-semibold mb-1">Important:</p>
                    <p>All payments and receipts are on the Solana network. Send USDT (SPL Token) on the Solana network only. Pay the exact SOL amount.</p>
                </div>
            </div>

            {/* Payment Details */}
            <div className="space-y-6 mb-8">
                <div className="bg-dark/50 rounded-xl p-4 border border-white/5">
                    <div className="flex justify-between items-center mb-1">
                        <span className="text-gray-400 text-sm">Total Amount</span>
                    </div>
                    <div className="flex items-end gap-2">
                        <span className="text-3xl font-mono font-bold text-secondary">{solAmount} SOL</span>
                        <span className="text-gray-500 mb-1">(${order.selectedPackage.priceUsd})</span>
                    </div>
                </div>

                <div className="bg-dark/50 rounded-xl p-4 border border-white/5">
                    <label className="text-gray-400 text-sm block mb-2">Deposit Address (Solana)</label>
                    <div className="flex items-center gap-2 bg-black/20 rounded-lg p-3 border border-white/5 break-all font-mono text-sm text-gray-200">
                        <span className="break-all">{RECIPIENT_WALLET}</span>
                        <button 
                            onClick={handleCopy}
                            className="p-2 hover:bg-white/10 rounded-md transition-colors shrink-0 text-primary"
                        >
                            {copied ? <Check size={18} /> : <Copy size={18} />}
                        </button>
                    </div>
                </div>
            </div>

            {/* Verification Form */}
            <div className="border-t border-white/10 pt-8">
                <h3 className="text-lg font-semibold text-white mb-4">Confirm Transaction</h3>
                <form onSubmit={handleVerify} className="space-y-4">
                    <div>
                        <label className="block text-sm font-medium text-gray-300 mb-2">
                            Transaction Hash / Signature
                        </label>
                        <input 
                            type="text" 
                            value={txHash}
                            onChange={(e) => setTxHash(e.target.value)}
                            className="w-full bg-dark/50 border border-white/10 rounded-xl py-3 px-4 text-white focus:outline-none focus:border-primary transition-all placeholder-gray-600 font-mono text-sm"
                            placeholder="Enter transaction hash (starts with 0x or similiar)"
                            required
                        />
                    </div>
                    <button 
                        type="submit"
                        disabled={isVerifying || !txHash}
                        className="w-full bg-secondary text-dark font-bold py-4 rounded-xl hover:bg-secondary/90 transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                    >
                        {isVerifying ? (
                            <>
                                <Loader2 className="animate-spin" size={20} />
                                Verifying on Blockchain...
                            </>
                        ) : (
                            'Verify Hash'
                        )}
                    </button>
                </form>
            </div>

        </div>
      </div>
    </div>
  );
};

