                </div>
            </div>

            {/* Payment Details */}
            <div className="space-y-6 mb-8">
                <div className="bg-dark/50 rounded-xl p-4 border border-white/5">
                    <div className="flex justify-between items-center mb-1">
                        <span className="text-gray-400 text-sm">Total Amount Due</span>
                    </div>
                    <div className="flex items-end gap-2">
                        <span className="text-3xl font-mono font-bold text-secondary">{order.selectedPackage.priceUsd} USDT</span>
                        <span className="text-gray-500 mb-1">(SPL)</span>
