                </div>

                <div className="bg-dark/50 rounded-xl p-4 border border-white/5">
                    <label className="text-gray-400 text-sm block mb-2">Merchant Address (Solana Network)</label>
                    <div className="flex items-center gap-2 bg-black/20 rounded-lg p-3 border border-white/5 break-all font-mono text-sm text-gray-200">
