import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useShop } from '../context/ShopContext';
import { RECIPIENT_WALLET } from '../constants';
import { SEO } from '../components/SEO';
import { Copy, AlertTriangle, Check, Loader2, ShieldCheck, Info } from 'lucide-react';

export const Payment: React.FC = () => {
  const { order, updateOrder } = useShop();
  const navigate = useNavigate();
  const [copied, setCopied] = useState(false);
  const [txHash, setTxHash] = useState('');
  const [isVerifying, setIsVerifying] = useState(false);
  const [error, setError] = useState('');

  if (!order.selectedPackage) {
    navigate('/');
    return null;
  }

  const handleCopy = () => {
    navigator.clipboard.writeText(RECIPIENT_WALLET);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleVerify = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!txHash) return;

    if (!txHash.startsWith('0x')) {
      setError('Invalid transaction hash. Must start with "0x".');
      return;
    }

    if (txHash.length < 60 || txHash.length > 70) {
      setError('Invalid transaction hash length. Please check your input.');
      return;
    }

    setIsVerifying(true);
    // Simulate network verification delay
    setTimeout(() => {
        setIsVerifying(false);
        updateOrder({ txHash });
        navigate('/confirmation');
    }, 4000);
  };

  return (
    <div className="min-h-screen pt-12 pb-24 px-4 bg-gradient-to-b from-dark to-slate-900">
      <SEO title="Secure Checkout" />
      <div className="max-w-2xl mx-auto">

        {/* Trust Banner */}
        <div className="flex items-center justify-center gap-2 mb-8 text-secondary/80 bg-secondary/5 py-2 px-4 rounded-full w-fit mx-auto border border-secondary/10">
          <ShieldCheck size={16} />
          <span className="text-xs font-semibold tracking-wide uppercase">Secure Solana Gateway</span>
        </div>

        <div className="bg-card/50 backdrop-blur-xl border border-white/10 rounded-3xl p-6 md:p-10 shadow-2xl relative overflow-hidden">
