            <div className="absolute top-0 right-0 w-64 h-64 bg-primary/5 rounded-full blur-3xl -translate-y-1/2 translate-x-1/2 pointer-events-none"></div>

            {/* Header */}
            <div className="text-center mb-10 relative z-10">
                <h2 className="text-3xl font-bold text-white mb-3">Complete Your Order</h2>
                <div className="flex items-center justify-center gap-2 text-gray-400">
                  <span>Package:</span>
                  <span className="text-white font-medium bg-white/5 px-2 py-0.5 rounded">{order.selectedPackage.flashAmount.toLocaleString()} Flash</span>
                </div>
            </div>

            {/* Critical Warning Box */}
            <div className="bg-orange-500/10 border border-orange-500/20 rounded-2xl p-5 mb-8 flex gap-4 items-start relative overflow-hidden group hover:bg-orange-500/15 transition-colors">
                <div className="bg-orange-500/20 p-2 rounded-lg shrink-0">
                  <AlertTriangle className="text-orange-500" size={24} />
                </div>
                <div className="text-sm text-orange-200/90 relative z-10">
                    <p className="font-bold mb-1 text-orange-100 uppercase tracking-wide flex items-center gap-2">
                      Important Reminder
                    </p>
                    <p className="leading-relaxed">
                      Only send <strong>USDT (Solana Network)</strong>. Do not send usdt in any other network.
                      <br/>
                      <span className="text-xs opacity-70 mt-1 block">Sending funds on the wrong network (like Ethereum/TRC20) will result in permanent loss.</span>
                    </p>
                </div>
            </div>

            {/* Payment Details */}
            <div className="space-y-6 mb-10 relative z-10">
                <div className="bg-dark/80 rounded-2xl p-5 border border-white/5 flex flex-col md:flex-row justify-between items-center gap-4">
                    <span className="text-gray-400 text-sm font-medium">Amount Required</span>
                    <div className="flex items-baseline gap-2">
                        <span className="text-4xl font-mono font-bold text-white tracking-tight">{order.selectedPackage.priceUsd}</span>
                        <span className="text-lg font-bold text-secondary">USDT</span>
                    </div>
                </div>

                <div className="bg-dark/80 rounded-2xl p-5 border border-white/5">
                    <div className="flex justify-between items-center mb-3">
                        <label className="text-gray-400 text-xs font-bold uppercase tracking-wider">Merchant Wallet Address</label>
                        <span className="text-[10px] text-primary bg-primary/10 px-2 py-0.5 rounded-full border border-primary/20">Solana Network</span>
                    </div>
                    <div className="flex items-center gap-3 bg-black/40 rounded-xl p-4 border border-white/5 group hover:border-primary/30 transition-colors">
                        <div className="break-all font-mono text-sm text-gray-200 flex-grow leading-relaxed">
                            {RECIPIENT_WALLET}
                        </div>
                        <button 
                            onClick={handleCopy}
                            className={`p-2.5 rounded-lg transition-all shrink-0 ${copied ? 'bg-secondary text-dark' : 'bg-white/5 text-gray-400 hover:bg-white/10 hover:text-white'}`}
                            title="Copy Address"
                        >
                            {copied ? <Check size={20} /> : <Copy size={20} />}
                        </button>
                    </div>
                    <div className="mt-3 flex items-start gap-2 text-xs text-gray-500 px-1">
                      <Info size={14} className="mt-0.5 shrink-0" />
                      <p>Copy the address above and send the exact USDT amount from your Phantom, Solflare, or Exchange wallet.</p>
                    </div>
                </div>
            </div>

            {/* Verification Form */}
            <div className="border-t border-white/10 pt-8 relative z-10">
                <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
                  <span className="w-6 h-6 rounded-full bg-primary/20 text-primary flex items-center justify-center text-xs">2</span>
                  Confirm Transaction
                </h3>
                <form onSubmit={handleVerify} className="space-y-5">
                    <div>
                        <input 
                            type="text" 
                            value={txHash}
                            onChange={(e) => {
                                setTxHash(e.target.value);
                                setError('');
