export const Payment: React.FC = () => {
  const { order, updateOrder } = useShop();
  const navigate = useNavigate();
  const [copied, setCopied] = useState(false);
  const [txHash, setTxHash] = useState('');
  const [isVerifying, setIsVerifying] = useState(false);
  const [error, setError] = useState('');

  if (!order.selectedPackage) {
    navigate('/');
    return null;
  }

  const handleCopy = () => {
    navigator.clipboard.writeText(RECIPIENT_WALLET);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleVerify = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!txHash) return;

    // Validation: Solana transaction signatures are base58 strings, typically 87-88 characters long.
    // Example: hvTpnrhJYZpo3hKnsT2tjBofQukbkK8USmBrHM6ptkqkgYXUToxVuafzYoQevAdUM6zfdqmkAMvwbmow5HjnGw4
    if (txHash.length < 80 || txHash.length > 100) {
      setError('Invalid transaction signature. Please enter a valid Solana transaction ID (approx 88 chars).');
      return;
    }

    setIsVerifying(true);
    // Simulate network verification delay
    setTimeout(() => {
        setIsVerifying(false);
        updateOrder({ txHash });
        navigate('/confirmation');
    }, 4000);
  };

  return (
    <div className="min-h-screen bg-dark pt-20 pb-24 px-4 relative overflow-hidden">
      <SEO title="Secure Checkout" />

